SELECT @pid, @lang_fr, 'Nous contacter', 'contact', '<p style="color:var(--sd-muted);font-size:1.08rem;line-height:1.7;max-width:640px;">Que vous prépariez une migration vers un cloud souverain, un audit, ou que vous pesiez simplement vos options, nos experts sont là pour vous aider. Écrivez-nous et nous vous recontacterons sous 24 heures ouvrées.</p><div class="row g-4 mt-1"><div class="col-md-4"><div class="sd-card h-100"><div class="sd-card-icon"><svg width="26" height="26" viewBox="0 0 24 24" fill="none"><rect x="3" y="5" width="18" height="14" rx="2" stroke="currentColor" stroke-width="2"/><path d="M4 7l8 6 8-6" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></div><h3>E-mail</h3><p><a href="mailto:contact@sovereignty.example" class="sd-card-link">contact@sovereignty.example</a></p></div></div><div class="col-md-4"><div class="sd-card h-100"><div class="sd-card-icon sd-card-icon-accent"><svg width="26" height="26" viewBox="0 0 24 24" fill="none"><path d="M5 4h4l2 5-3 2a12 12 0 005 5l2-3 5 2v4a2 2 0 01-2 2A16 16 0 013 6a2 2 0 012-2z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/></svg></div><h3>Téléphone</h3><p><a href="tel:+442012345678" class="sd-card-link">+44 20 1234 5678</a></p></div></div><div class="col-md-4"><div class="sd-card h-100"><div class="sd-card-icon sd-card-icon-orange"><svg width="26" height="26" viewBox="0 0 24 24" fill="none"><path d="M12 22s8-7 8-12a8 8 0 10-16 0c0 5 8 12 8 12z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><circle cx="12" cy="10" r="3" stroke="currentColor" stroke-width="2"/></svg></div><h3>Bureaux</h3><p>Londres &middot; Paris &middot; Bruxelles &middot; Luxembourg</p></div></div></div>', '', 'contact, souveraineté numérique, consultation, devis, RGPD', 'Échangez avec nos experts en souveraineté numérique. Consultation gratuite et confidentielle, réponse sous 24 heures ouvrées.'
WHERE @lang_fr IS NOT NULL AND @pid IS NOT NULL AND @fr_done = 0;

