SELECT @pid, @lang_fr, 'Méthode & Certifications', 'certifications', '<div class="sd-section-header"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Notre méthode</span><h2>Un parcours clair en <span class="sd-gradient-text">4 étapes</span></h2><p class="section-lead">De la première analyse à la mise en production, nous suivons une méthode éprouvée auprès de plus de 250 organisations européennes.</p></div><div class="row g-4"><div class="col-md-6 col-lg-3"><div class="sd-step"><div class="sd-step-number">01</div><div class="sd-step-icon"><svg width="22" height="22" viewBox="0 0 24 24" fill="none"><circle cx="11" cy="11" r="7" stroke="currentColor" stroke-width="2"/><path d="M21 21l-4.35-4.35" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg></div><h3>Audit &amp; Cartographie</h3><p>Nous cartographions vos données, vos charges et votre exposition réglementaire pour identifier ce qui requiert réellement la souveraineté.</p></div></div><div class="col-md-6 col-lg-3"><div class="sd-step"><div class="sd-step-number">02</div><div class="sd-step-icon"><svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8l-6-6z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M14 2v6h6" stroke="currentColor" stroke-width="2"/></svg></div><h3>Stratégie sur Mesure</h3><p>Une feuille de route alignée sur les contraintes de votre secteur, votre budget et vos outils existants.</p></div></div><div class="col-md-6 col-lg-3"><div class="sd-step"><div class="sd-step-number">03</div><div class="sd-step-icon"><svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M12 2v4M12 18v4M2 12h4M18 12h4M5 5l3 3M16 16l3 3M19 5l-3 3M8 16l-3 3" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><circle cx="12" cy="12" r="3" stroke="currentColor" stroke-width="2"/></svg></div><h3>Mise en Œuvre</h3><p>Migration et intégration avec réversibilité garantie et sans verrouillage caché.</p></div></div><div class="col-md-6 col-lg-3"><div class="sd-step"><div class="sd-step-number">04</div><div class="sd-step-icon"><svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M3 12a9 9 0 1015.5-6.3" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M18 3v4h-4" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></div><h3>Exploitation &amp; Amélioration</h3><p>Supervision continue, optimisation et support 24/7 assurés par nos équipes européennes.</p></div></div></div><div class="sd-section-header" style="margin-top:4rem;"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Certifications</span><h2>Des standards reconnus, audités et <span class="sd-gradient-text">vérifiables</span></h2><p class="section-lead">Nous opérons selon les référentiels les plus exigeants. Chacun de nos services est certifié par des auditeurs indépendants accrédités.</p></div><div class="row g-3 g-md-4"><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M9 12l2 2 4-4" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></div><h4>SecNumCloud</h4><p>ANSSI 3.2</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="9" stroke="currentColor" stroke-width="2"/><text x="12" y="15" text-anchor="middle" font-size="6" font-weight="700" fill="currentColor">ISO</text></svg></div><h4>ISO 27001</h4><p>Management SSI</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><path d="M12 3l2.5 5 5.5.8-4 3.9 1 5.5-5-2.6-5 2.6 1-5.5-4-3.9 5.5-.8z" stroke="currentColor" stroke-width="1.8" stroke-linejoin="round"/></svg></div><h4>HDS</h4><p>Données de santé</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><rect x="4" y="9" width="16" height="12" rx="2" stroke="currentColor" stroke-width="2"/><path d="M8 9V6a4 4 0 018 0v3" stroke="currentColor" stroke-width="2"/></svg></div><h4>RGPD</h4><p>Conformité UE</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="9" stroke="currentColor" stroke-width="2"/><path d="M3 12h18M12 3a14 14 0 010 18M12 3a14 14 0 000 18" stroke="currentColor" stroke-width="1.5"/></svg></div><h4>NIS2</h4><p>Directive UE</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><path d="M5 7l7-4 7 4v6c0 5-3.5 7.5-7 9-3.5-1.5-7-4-7-9z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M12 8v4l2 2" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></div><h4>SOC 2</h4><p>Type II</p></div></div></div><div class="row g-4" style="margin-top:3.5rem;"><div class="col-6 col-md-3"><div class="sd-stat"><div class="sd-stat-number">250+</div><div class="sd-stat-label">Organisations accompagnées</div></div></div><div class="col-6 col-md-3"><div class="sd-stat"><div class="sd-stat-number">99.99%</div><div class="sd-stat-label">Disponibilité SLA moyenne</div></div></div><div class="col-6 col-md-3"><div class="sd-stat"><div class="sd-stat-number">14</div><div class="sd-stat-label">Pays européens</div></div></div><div class="col-6 col-md-3"><div class="sd-stat"><div class="sd-stat-number">24/7</div><div class="sd-stat-label">SOC souverain</div></div></div></div>', '', 'méthode, certifications, SecNumCloud, ISO 27001, HDS, RGPD, NIS2, SOC 2', 'Notre méthode éprouvée en 4 étapes et les certifications reconnues (SecNumCloud, ISO 27001, HDS, RGPD, NIS2, SOC 2) qui sous-tendent nos solutions souveraines.'
WHERE @lang_fr IS NOT NULL AND @pid IS NOT NULL AND @fr_done = 0;

-- Cloud Souverain
SET @pid := (SELECT post_id FROM post_content WHERE slug = 'sovereign-cloud' AND language_id = @lang ORDER BY post_id LIMIT 1);
