INSERT INTO post_content (post_id, language_id, name, slug, content, excerpt, meta_keywords, meta_description)
SELECT @pid, @lang_fr, 'Cybersécurité & SOC', 'cybersecurite-soc', '<div class="sd-section-header"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Cybersécurité &amp; SOC</span><h2>Détection des menaces 24/7 depuis un <span class="sd-gradient-text">SOC souverain</span></h2><p class="section-lead">Un centre des opérations de sécurité (SOC) européen infogéré qui surveille vos charges critiques en continu. Détectez, investiguez et répondez aux menaces plus vite &mdash; avec analystes, outils et données conservés en Europe.</p></div><div class="row g-4"><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>SOC infogéré 24/7</h3><p>Des analystes européens surveillent votre environnement jour et nuit, trient les alertes et escaladent les vrais incidents en quelques minutes.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Détection &amp; réponse aux menaces</h3><p>SIEM, EDR et renseignement sur les menaces réunis dans un service de détection et réponse gérées (MDR) calibré sur votre profil de risque.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Tests d\'intrusion</h3><p>Missions de sécurité offensive et exercices red-team qui révèlent les failles avant les attaquants.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Réponse à incident</h3><p>Un plan d\'action éprouvé et des experts d\'astreinte pour contenir, éradiquer et se relever des incidents avec un impact minimal.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Gestion des vulnérabilités</h3><p>Analyse continue, priorisation et suivi de la remédiation sur l\'ensemble de vos applications et infrastructures.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Préparation NIS2</h3><p>Contrôles, reporting et gouvernance alignés sur la directive NIS2 pour les entités essentielles et importantes.</p></div></div></div><div class="sd-section-header" style="margin-top:3rem;"><p class="section-lead">Les attaquants n\'ont pas d\'horaires de bureau &mdash; nous non plus. Découvrez comment un SOC souverain renforce votre défense.</p><a href="/fr/page/contact" class="sd-btn sd-btn-primary">Réserver une consultation SOC <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div>', '', 'cybersécurité, SOC infogéré, MDR, détection des menaces, test d\'intrusion, réponse à incident, NIS2', 'SOC souverain infogéré 24/7 : détection et réponse aux menaces, tests d\'intrusion, réponse à incident et préparation NIS2 pour vos charges critiques européennes.'
WHERE @lang_fr IS NOT NULL AND @pid IS NOT NULL AND @fr_done = 0;

