INSERT INTO post_content (post_id, language_id, name, slug, content, excerpt, meta_keywords, meta_description)
SELECT @pid, @lang_fr, 'Stratégie & Conseil', 'strategie-conseil', '<div class="sd-section-header"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Stratégie &amp; Conseil</span><h2>Une <span class="sd-gradient-text">feuille de route de souveraineté</span> pragmatique pour votre DSI</h2><p class="section-lead">Nous cartographions vos dépendances numériques, quantifions le risque de verrouillage étranger et bâtissons une feuille de route pluriannuelle équilibrant souveraineté, coût et performance &mdash; alignée sur votre secteur, votre budget et vos outils existants.</p></div><div class="row g-4"><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Cartographie des dépendances</h3><p>Une vision claire des fournisseurs, flux de données et charges qui vous exposent au risque extraterritorial.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Analyse des risques</h3><p>Évaluation quantifiée des risques de verrouillage, réglementaires et de continuité, priorisés par impact métier.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Feuille de route de souveraineté</h3><p>Un plan pluriannuel réaliste avec jalons, budgets et gains rapides que votre direction pourra soutenir.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Revue des fournisseurs &amp; outils</h3><p>Évaluation indépendante des alternatives souveraines adaptées à votre stack, sans tout remplacer.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Étude de rentabilité &amp; TCO</h3><p>Un modèle de coûts et de valeur défendable pour justifier et financer facilement les investissements de souveraineté.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Conduite du changement &amp; gouvernance</h3><p>Modèle opérationnel, gouvernance et indicateurs pour maintenir le cap de la souveraineté bien après la fin du projet.</p></div></div></div><div class="sd-section-header" style="margin-top:3rem;"><p class="section-lead">La souveraineté est un cheminement, pas un interrupteur. Commencez par une feuille de route claire et chiffrée, bâtie autour de votre réalité.</p><a href="/fr/page/contact" class="sd-btn sd-btn-primary">Planifier votre feuille de route <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div>', '', 'stratégie de souveraineté numérique, conseil informatique, cartographie des dépendances, analyse des risques, feuille de route DSI', 'Conseil en souveraineté numérique : cartographie des dépendances, analyse des risques et feuille de route pluriannuelle pragmatique, alignée sur votre secteur, votre budget et vos outils.'
